DROP TABLE IF EXISTS poi CASCADE;
CREATE TABLE poi (
    id SERIAL PRIMARY KEY,
    osm_id TEXT UNIQUE NOT NULL,
    name TEXT,
    highway TEXT,
    natural_kind TEXT,
    surface TEXT,
    geom GEOMETRY(Point, 4326) NOT NULL
);

